var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"캬아아███!!","JPN":"キャア███！！","ENG":"Kya███!","TWN":"咳啊啊███！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"......또 부활한 건가? 대체 얼마나 쓰러트려야 하는 거야?","JPN":"……また復活したか！　いったい何回倒せばいいの？","ENG":"Did she come back to life again? How many times do I have to defeat her?","TWN":"……又復活了嗎？到底要打倒幾次才行？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이래선...... 리플레이서 녀석들과 다를 게 없잖아.","JPN":"このままじゃ……リプレイサーの奴らと変わらない。","ENG":"She's like... the Replacers.","TWN":"這樣的話……跟克隆集團的傢伙沒什麼兩樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 녀석이 리플레이서와 관련이 있을 리는 없는데, 대체 어떻게......","JPN":"こいつがリプレイサーと関連しているはずがない。でもどうして……","ENG":"But she couldn't possibly have anything to do with them... So how come...","TWN":"這傢伙不可能跟克隆集團有關，到底為什麼……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"크윽!","JPN":"くっ！","ENG":"Hngh!","TWN":"呃啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네가 돕지 않으면 그녀는 패배할 거다, 레이.","JPN":"お前が助けないと彼女は負けてしまうぞ、レイ。","ENG":"She will be defeated without your help, Ray.","TWN":"如果你不幫忙的話，她一定會失敗的，雷伊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그렇게 되면...... 우리는 또다시 모든 희망을 잃고 공허 속을 헤매야 하겠지.","JPN":"そうなると……我々はまたすべての希望を失い、空虚の中を彷徨うことになるだろう。","ENG":"And if it comes to that... We shall lose all hope again, and wander aimlessly through the void.","TWN":"那樣的話……我們又要失去所有希望，在虛空中遊蕩。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이제는 모든 것들을 제자리로 돌릴 때가 됐어.","JPN":"今はすべてを元のあるべき場所に戻す時となった。","ENG":"It is time to return everything to its rightful place.","TWN":"現在到了讓所有東西歸位的時候了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이, 네 힘이 필요하다.","JPN":"レイ、お前の力が必要だ。","ENG":"She needs your help, Ray.","TWN":"雷伊，我需要你的力量。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......이러지 마.","JPN":"……やめて。","ENG":"Don't do this to me.","TWN":"……不要這樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"제발 부탁이야. 난 그러고 싶지 않아.","JPN":"お願い、僕は嫌だよ。","ENG":"Please. I really don't want to.","TWN":"求求你，我真的不想這樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"언제까지 현실을 외면하기만 할 거냐!","JPN":"いつまで現実から目を背けるつもりだ？","ENG":"How long will you continue to turn a blind eye to reality?","TWN":"你想逃避現實到什麼時候？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"우리 모두가...... 네게 어떤 기대를 걸고 있는지 알고 있잖아.","JPN":"私たちが……お前にどれだけ期待しているかわかっているはずだ。","ENG":"All of us are counting on you... You know that.","TWN":"你清楚我們所有人……對你的期待是什麼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"난...... 난 더 이상 기대 받고 싶지 않아!","JPN":"僕は……僕はもう期待なんかされたくないんだ！","ENG":"I... I don't want anyone to count on me anymore!","TWN":"我……我再也不想受到期待了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"난 실패자라고! 내게 기회 같은 건 없어!","JPN":"僕は失敗者だから！　チャンスなどない！","ENG":"I'm a failure! There is no second chance for me!","TWN":"我是失敗者！對我來說沒有機會了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 대체 왜 날 계속 괴롭히는 거야? 이제 제발 그만 내버려 둬!","JPN":"なのにどうして僕にずっと付きまとう？　もう放っておいて！","ENG":"Why do you keep harassing me? Just leave me in peace now!","TWN":"你們為什麼還糾纏我？拜託，放過我吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};